window.docContents[95].resolve({"/Documentation-Features/#Zippers___-A-Documentation-Example--Documentation-Features":{"contents":"The code example utilities used to document external projects have a systematic set of names, whether used as code blocks or roles.\nAll documentation tools draw their code from an example project:\n\nThe directory in which to search for example code\n\nThe example project must depend on the same version of subverso that the document's Verso version uses.\n\nWithin the example project, examples are drawn from a module.\nSometimes, the entire module is the example, while other cases use just some part of the module.\nTo set a default module, use the option verso.exampleModule.\nWhen there is no default set, or to override it, the example code features all accept a keyword argument module.\n\nThe default module to load examples from\n\n\n\n\n\n","context":"Zippers: A Documentation Example","header":"2. Documentation Features","id":"/Documentation-Features/#Zippers___-A-Documentation-Example--Documentation-Features"}});